INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 1, 'en', 'How do I start ordering through THG?', 'Simple! Just copy the product link from Taobao, 1688, or Pinduoduo and send it to us via Facebook. THG will verify the supplier, quote an all-in price, and guide you through each step.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 1, 'vi', 'Tôi cần làm gì để bắt đầu đặt hàng qua THG?', 'Rất đơn giản! Copy link sản phẩm từ Taobao, 1688 hoặc Pinduoduo gửi cho chúng tôi qua Facebook. THG sẽ kiểm tra nhà cung cấp, báo giá trọn gói và hướng dẫn từng bước.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 1, 'zh', '如何开始通过THG订购？', '很简单!复制淘宝、1688或拼多多的商品链接,通过Facebook发给我们。THG将验证供应商、报全包价并逐步指导您。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 2, 'en', 'How long does shipping from China to USA take?', '• Standard Air (Epacket): 6–12 Business Days' || CHAR(10) || '• Express Air (DHL/FedEx): 3–5 Business Days' || CHAR(10) || '• Sea Freight (Bulk): 20–25 Business Days' || CHAR(10) || '' || CHAR(10) || 'Vs. routing through Vietnam, you save 3–4 extra weeks and $150–300.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 2, 'vi', 'Thời gian từ lúc đặt hàng đến khi nhận hàng tại Mỹ mất bao lâu?', '• Hàng không thường (Epacket): 6–12 Ngày LV' || CHAR(10) || '• Hàng không nhanh (DHL/FedEx): 3–5 Ngày LV' || CHAR(10) || '• Hàng lô đường biển: 20–25 Ngày LV' || CHAR(10) || '' || CHAR(10) || 'So với đi vòng qua Việt Nam, bạn tiết kiệm 3–4 tuần và $150–300.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 2, 'zh', '从中国到美国的运输需要多长时间?', '• 标准空运(Epacket): 6-12个工作日' || CHAR(10) || '• 快速空运(DHL/FedEx): 3-5个工作日' || CHAR(10) || '• 海运(散货): 20-25个工作日' || CHAR(10) || '' || CHAR(10) || '比经越南中转节省3-4周和$150-300。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 3, 'en', 'How do I pay THG from the USA?', '• PayPal (most common for US-based customers)' || CHAR(10) || '• Pingpong / Payoneer / WorldFirst' || CHAR(10) || '• VND bank transfer' || CHAR(10) || '• Zelle / Venmo (USD)' || CHAR(10) || '' || CHAR(10) || 'Payment: 50% deposit when confirming, 50% balance when ready to ship.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 3, 'vi', 'Tôi ở Mỹ thanh toán cho THG bằng cách nào?', '• PayPal (phổ biến nhất với khách tại Mỹ)' || CHAR(10) || '• Pingpong / Payoneer / WorldFirst' || CHAR(10) || '• Chuyển khoản VND' || CHAR(10) || '• Zelle / Venmo (USD)' || CHAR(10) || '' || CHAR(10) || 'Quy trình: Đặt cọc 50% khi xác nhận, thanh toán 50% còn lại khi hàng sẵn sàng ship.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 3, 'zh', '在美国如何付款给THG?', '• PayPal(美国客户最常用)' || CHAR(10) || '• Pingpong/Payoneer/WorldFirst' || CHAR(10) || '• 越南盾银行转账' || CHAR(10) || '• Zelle/Venmo (USD)' || CHAR(10) || '' || CHAR(10) || '付款:确认时预付50%,发货前付清余款。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 4, 'en', 'What if my goods arrive defective or don''t match the description?', '• All goods inspected and video-recorded before shipping' || CHAR(10) || '• Defect found BEFORE shipping → THG exchanges or refunds with supplier' || CHAR(10) || '• Defective after arrival → THG supports insurance claims' || CHAR(10) || '' || CHAR(10) || 'You NEVER have to contact the Chinese supplier directly.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 4, 'vi', 'Nếu hàng về bị lỗi hoặc không đúng mô tả, THG xử lý như thế nào?', '• Tất cả hàng được kiểm tra và quay video trước khi ship' || CHAR(10) || '• Phát hiện lỗi TRƯỚC khi ship → THG đổi hàng hoặc hoàn tiền' || CHAR(10) || '• Hàng lỗi SAU khi đến Mỹ → THG hỗ trợ bảo hiểm và bồi thường' || CHAR(10) || '' || CHAR(10) || 'Bạn KHÔNG BAO GIỜ phải tự liên hệ nhà cung cấp.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 4, 'zh', '如果收到的商品有缺陷或与描述不符怎么办?', '• 发货前所有商品进行检查和录像' || CHAR(10) || '• 发货前发现缺陷 → THG与供应商换货或退款' || CHAR(10) || '• 到达后有缺陷 → THG支持保险索赔' || CHAR(10) || '' || CHAR(10) || '您永远不需要直接联系中国供应商。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 5, 'en', 'Will I have to pay US customs / import tax?', '• Epacket Yun Express: Tax INCLUDED in shipping price' || CHAR(10) || '• Standard Epacket: THG handles tax declaration' || CHAR(10) || '• Bulk Sea: US customs collects duty from recipient' || CHAR(10) || '' || CHAR(10) || 'THG advises best lane for your goods to minimize customs costs.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 5, 'vi', 'Hàng có bị thuế hải quan khi nhập vào Mỹ không?', '• Epacket Yun Express: Thuế đã BAO GỒM trong giá ship' || CHAR(10) || '• Epacket thường: THG xử lý khai báo thuế' || CHAR(10) || '• Hàng lô đường biển: Hải quan Mỹ thu trực tiếp từ người nhận' || CHAR(10) || '' || CHAR(10) || 'THG sẽ tư vấn kênh tốt nhất để tối thiểu hóa chi phí hải quan.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 5, 'zh', '需要缴纳美国海关/进口税吗?', '• Epacket云途:运费已含税' || CHAR(10) || '• 标准Epacket: THG处理报关' || CHAR(10) || '• 散货海运:美国海关向收件人征收关税' || CHAR(10) || '' || CHAR(10) || 'THG建议最佳渠道以最小化海关费用。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 6, 'en', 'Can THG find and compare products for me from multiple suppliers?', 'Absolutely! THG searches Taobao, 1688, and Pinduoduo, compares 3–5 suppliers, verifies ratings & quality in Mandarin, and presents a quoted comparison. This sourcing service is 100% FREE.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 6, 'vi', 'THG có thể tìm và so sánh sản phẩm tốt nhất từ nhiều nhà cung cấp không?', 'Hoàn toàn có! THG tìm trên Taobao, 1688, Pinduoduo và so sánh 3–5 nhà cung cấp, kiểm tra đánh giá bằng tiếng Trung. Dịch vụ tìm hàng này 100% MIỄN PHÍ.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 6, 'zh', 'THG能帮我从多个供应商找到并比较产品吗?', '当然!THG搜索淘宝、1688和拼多多,比较3-5个供应商,用中文验证评分和质量,提供报价比较。此采购服务100%免费。');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 7, 'en', 'Where are THG''s warehouses? Can I pick up in Pennsylvania?', 'THG operates 3 locations:' || CHAR(10) || '• 🇻🇳 Vietnam: 121/5 Kenh 19/5 St., Son Ky, Tan Phu, HCMC' || CHAR(10) || '• 🇨🇳 China: Dongguan, Guangdong' || CHAR(10) || '• 🇺🇸 USA: 108 Almond CT, Milford, PA 18337' || CHAR(10) || '' || CHAR(10) || 'Customers near PA can arrange direct pickup.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 7, 'vi', 'THG có kho ở đâu? Tôi ở Pennsylvania có thể lấy hàng không?', 'THG có 3 địa điểm:' || CHAR(10) || '• 🇻🇳 Việt Nam: 121/5 Đ. Kênh 19/5, Sơn Kỳ, Tân Phú, TP.HCM' || CHAR(10) || '• 🇨🇳 Trung Quốc: Đông Hoản, Quảng Đông' || CHAR(10) || '• 🇺🇸 Mỹ: 108 Almond CT, Milford, PA 18337' || CHAR(10) || '' || CHAR(10) || 'Khách gần PA có thể đến lấy hàng trực tiếp.');
INSERT INTO faqs (scope, position, locale, question, answer) VALUES ('order', 7, 'zh', 'THG的仓库在哪里?可以在宾州自提吗?', 'THG运营3个地点:' || CHAR(10) || '• 🇻🇳 越南:胡志明市新富区' || CHAR(10) || '• 🇨🇳 中国:广东东莞' || CHAR(10) || '• 🇺🇸 美国:108 Almond CT, Milford, PA 18337' || CHAR(10) || '' || CHAR(10) || '宾州附近的客户可以安排自提。');
